using namespace std;

long long solve(vector<long long> nums) {
    int n = nums.size();
    if (n == 0) return 0;

    // Function to check if a number is prime
    auto isPrime = [](long long x) {
        if (x < 2) return false;
        for (long long i = 2; i * i <= x; ++i) {
            if (x % i == 0) return false;
        }
        return true;
    };

    // BFS to find the minimum number of jumps
    queue<int> q;
    q.push(0);
    vector<bool> visited(n, false);
    visited[0] = true;
    int steps = 0;

