            int curr = q.front();
            q.pop();

            if (curr == n - 1) return steps;

            // Move to adjacent cells
            if (curr > 0 && !visited[curr - 1]) {
                visited[curr - 1] = true;
                q.push(curr - 1);
            }
            if (curr < n - 1 && !visited[curr + 1]) {
                visited[curr + 1] = true;
                q.push(curr + 1);
            }

            // Prime teleportation
            if (isPrime(nums[curr])) {
                long long p = nums[curr];
                // Find all indices j where nums[j] % p == 0
                set<int> targets;
                for (int j = 0; j < n; ++j) {
                    if (j != curr && nums[j] % p == 0) {
                        targets.insert(j);
                    }
                }
                // Add all targets to the queue
                for (int j : targets) {
                    if (!visited[j]) {
                        visited[j] = true;
                        q.push(j);
                    }
                }
            }
        }
        steps++;
    }

    return -1; // If not reachable
}

